import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { Search as SearchIcon, Music, Play, ArrowLeft, XCircle, Heart } from 'lucide-react';

const Search = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();
  const loggedInUser = JSON.parse(localStorage.getItem('user'));

  // Xử lý tìm kiếm bài hát
  const handleSearch = async (e) => {
    const value = e.target.value;
    setSearchQuery(value);

    if (value.trim().length > 0) {
      setLoading(true);
      try {
        const res = await axios.get(`http://localhost:5000/api/songs/search?q=${value}`);
        setResults(res.data);
      } catch (err) {
        console.error("Lỗi tìm kiếm:", err);
      } finally {
        setLoading(false);
      }
    } else {
      setResults([]);
    }
  };

  return (
    <div style={{ padding: '40px 60px', maxWidth: '1200px', margin: '0 auto', fontFamily: 'Arial, sans-serif' }}>
      
      {/* HEADER & BACK BUTTON */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '50px' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
            <button onClick={() => navigate('/')} style={backBtnStyle}>
                <ArrowLeft size={24} />
            </button>
            <h1 style={{ color: '#1db954', margin: 0, display: 'flex', alignItems: 'center', gap: '10px', fontSize: '28px', fontWeight: '900' }}>
                <Music size={32} /> IAMNHAC
            </h1>
        </div>
        <div style={{ color: '#888', fontSize: '14px', fontWeight: 'bold' }}>TÌM KIẾM ÂM NHẠC</div>
      </div>

      {/* SEARCH INPUT AREA */}
      <div style={{ position: 'relative', maxWidth: '700px', margin: '0 auto 60px auto' }}>
        <SearchIcon 
            style={{ position: 'absolute', left: '25px', top: '50%', transform: 'translateY(-50%)', color: '#1db954' }} 
            size={24} 
        />
        <input 
          type="text"
          placeholder="Bạn muốn nghe gì hôm nay? (Tên bài hát, ca sĩ...)"
          value={searchQuery}
          onChange={handleSearch}
          style={searchInputStyle}
        />
      </div>

      {/* RESULTS AREA */}
      <div>
        {loading ? (
            <div style={{ textAlign: 'center', color: '#666', marginTop: '50px' }}>Đang tìm kiếm...</div>
        ) : results.length > 0 ? (
          <>
            <h2 style={{ fontSize: '22px', marginBottom: '25px', color: '#111' }}>Kết quả tìm kiếm cho "{searchQuery}"</h2>
            <div style={gridStyle}>
              {results.map((song) => (
                <div key={song._id} style={songCard} onClick={() => navigate('/', { state: { playId: song._id } })}>
                  <div style={{ position: 'relative', overflow: 'hidden', borderRadius: '15px' }}>
                    <img src={`http://localhost:5000${song.imageUrl}`} alt="" style={imgStyle} />
                    <button style={playOverlayBtn}>
                      <Play fill="white" size={20} />
                    </button>
                  </div>
                  <h3 style={{ margin: '15px 0 5px 0', fontSize: '17px', fontWeight: 'bold' }}>{song.title}</h3>
                  <p style={{ color: '#666', fontSize: '14px', margin: 0 }}>{song.artist}</p>
                </div>
              ))}
            </div>
          </>
        ) : searchQuery && !loading ? (
          <div style={emptyStateStyle}>
            <XCircle size={60} color="#ccc" strokeWidth={1} />
            <p style={{ marginTop: '20px', fontSize: '18px', color: '#999' }}>Không tìm thấy bài hát nào phù hợp với "{searchQuery}"</p>
          </div>
        ) : (
          <div style={welcomeSearchStyle}>
            <SearchIcon size={80} color="#eee" strokeWidth={1} />
            <p>Nhập tên bài hát hoặc nghệ sĩ để khám phá thế giới âm nhạc tại IAMNHAC</p>
          </div>
        )}
      </div>
    </div>
  );
};

/* --- STYLES --- */
const searchInputStyle = {
  width: '100%',
  padding: '18px 30px 18px 65px',
  fontSize: '18px',
  borderRadius: '40px',
  border: '2px solid #eee',
  outline: 'none',
  transition: 'all 0.3s ease',
  boxShadow: '0 10px 30px rgba(0,0,0,0.05)',
  backgroundColor: '#fff',
  // Khi focus sẽ có viền xanh
  ':focus': {
    borderColor: '#1db954',
    boxShadow: '0 10px 30px rgba(29, 185, 84, 0.1)'
  }
};

const backBtnStyle = {
  background: '#f5f5f5',
  border: 'none',
  width: '45px',
  height: '45px',
  borderRadius: '50%',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  cursor: 'pointer',
  transition: '0.2s',
  color: '#333'
};

const gridStyle = {
  display: 'grid',
  gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))',
  gap: '30px'
};

const songCard = {
  background: '#fff',
  padding: '15px',
  borderRadius: '20px',
  cursor: 'pointer',
  transition: 'transform 0.3s ease, box-shadow 0.3s ease',
  border: '1px solid #f0f0f0',
  ':hover': {
    transform: 'translateY(-8px)',
    boxShadow: '0 15px 35px rgba(0,0,0,0.1)'
  }
};

const imgStyle = {
  width: '100%',
  aspectRatio: '1/1',
  objectFit: 'cover',
  borderRadius: '12px',
  transition: 'transform 0.5s ease'
};

const playOverlayBtn = {
  position: 'absolute',
  bottom: '12px',
  right: '12px',
  background: '#1db954',
  border: 'none',
  borderRadius: '50%',
  width: '42px',
  height: '42px',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  cursor: 'pointer',
  color: 'white',
  boxShadow: '0 4px 10px rgba(0,0,0,0.2)'
};

const emptyStateStyle = {
  textAlign: 'center',
  marginTop: '100px',
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center'
};

const welcomeSearchStyle = {
  textAlign: 'center',
  marginTop: '100px',
  color: '#bbb',
  fontSize: '16px',
  maxWidth: '400px',
  margin: '100px auto',
  lineHeight: '1.6'
};

export default Search;
